   271→async function qFlush(){
   272→  if(!navigator.onLine)return;
   273→  const q=qLoad();
   274→  if(q.length===0)return;
   275→  qSave([]); // optimistically clear
   276→  try{
   277→    await Promise.all(q.map(op=>{
   278→      if(op.type==='upsertTask')return sb.from('tasks').upsert(op.data);
   279→      if(op.type==='deleteTask')return sb.from('tasks').delete().eq('id',op.id);
   280→      if(op.type==='upsertForward')return sb.from('forward_tasks').upsert(op.data);
   281→      if(op.type==='deleteForward')return sb.from('forward_tasks').delete().eq('id',op.id);
   282→    }));
   283→  }catch(e){
   284→    // restore queue if flush fails
   285→    const remaining=qLoad();
   286→    qSave([...q,...remaining]);
   287→    throw e;
   288→  }
   289→}
